parameters.jsCode:
// Parse Claude extraction response and build INSERT data
const input = $input.first().json;
const emailData = $('Build Extraction Prompts').item.json;

let extracted = {};
let inputTokens = 0;
let outputTokens = 0;

try {
  const body = input.body || input;
  inputTokens = body.usage?.input_tokens || 0;
  outputTokens = body.usage?.output_tokens || 0;

  const content = body.content?.[0]?.text || '';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    extracted = JSON.parse(jsonMatch[0]);
  }
} catch (err) {
  extracted = { extraction_confidence: 0, extraction_notes: `Parse error: ${err.message}` };
}

const costUsd = (inputTokens * 0.25 / 1000000) + (outputTokens * 1.25 / 1000000);

// Sanitize strings for SQL
const s = (val) => val ? String(val).replace(/'/g, "''").substring(0, 500) : null;
const sqlStr = (val) => val ? `'${s(val)}'` : 'NULL';
const sqlNum = (val) => (val !== null && val !== undefined && !isNaN(val)) ? val : 'NULL';
const sqlBool = (val) => val ? 'true' : 'false';
const sqlDate = (val) => val ? `'${val}'` : 'NULL';
const sqlJson = (val) => val ? `'${JSON.stringify(val).replace(/'/g, "''")}'::jsonb` : "'[]'::jsonb";

return [{
  json: {
    email_id: emailData.id,
    classification: emailData.classification,
    is_urgent: emailData.is_urgent,
    extracted,
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    cost_usd: costUsd,
    // Pre-formatted SQL values
    sql: {
      company_name: sqlStr(extracted.company_name),
      role_title: sqlStr(extracted.role_title),
      contact_person: sqlStr(extracted.contact_person),
      contact_email: sqlStr(extracted.contact_email),
      contact_phone: sqlStr(extracted.contact_phone),
      next_steps: sqlStr(extracted.next_steps),
      response_deadline: sqlDate(extracted.response_deadline),
      interview_date: sqlDate(extracted.interview_date),
      interview_time: extracted.interview_time ? `'${extracted.interview_time}'` : 'NULL',
      interview_timezone: sqlStr(extracted.interview_timezone || 'Europe/London'),
      interview_duration: sqlStr(extracted.interview_duration),
      interview_format: sqlStr(extracted.interview_format),
      interview_platform: sqlStr(extracted.interview_platform),
      interview_location: sqlStr(extracted.interview_location),
      interview_link: sqlStr(extracted.interview_link),
      interviewer_name: sqlStr(extracted.interviewer_name),
      interviewer_title: sqlStr(extracted.interviewer_title),
      interviewer_email: sqlStr(extracted.interviewer_email),
      preparation_instructions: sqlStr(extracted.preparation_instructions),
      what_to_bring: sqlStr(extracted.what_to_bring),
      dress_code: sqlStr(extracted.dress_code),
      rejection_reason: sqlStr(extracted.rejection_reason),
      rejection_stage: sqlStr(extracted.rejection_stage),
      feedback_offered: sqlBool(extracted.feedback_offered),
      reference_number: sqlStr(extracted.reference_number),
      review_timeline: sqlStr(extracted.review_timeline),
      expected_response_date: sqlDate(extracted.expected_response_date),
      recruiter_name: sqlStr(extracted.recruiter_name),
      recruiter_email: sqlStr(extracted.recruiter_email),
      recruiter_phone: sqlStr(extracted.recruiter_phone),
      agency_name: sqlStr(extracted.agency_name),
      proposed_role_title: sqlStr(extracted.proposed_role_title),
      proposed_company: sqlStr(extracted.proposed_company),
      proposed_salary_raw: sqlStr(extracted.proposed_salary_raw),
      proposed_salary_min: sqlNum(extracted.proposed_salary_min),
      proposed_salary_max: sqlNum(extracted.proposed_salary_max),
      proposed_location: sqlStr(extracted.proposed_location),
      salary_offered: sqlNum(extracted.salary_offered),
      salary_details: sqlStr(extracted.salary_details),
      start_date: sqlDate(extracted.start_date),
      offer_conditions: sqlJson(extracted.offer_conditions),
      action_required: sqlStr(extracted.action_required),
      action_deadline: sqlDate(extracted.action_deadline),
      documents_requested: sqlJson(extracted.documents_requested),
      source_platform: sqlStr(extracted.source_platform),
      jobs_listed: sqlJson(extracted.jobs_listed),
      total_jobs_count: sqlNum(extracted.total_jobs_count),
      extraction_confidence: sqlNum(extracted.extraction_confidence || 0.5),
      extraction_notes: sqlStr(extracted.extraction_notes)
    }
  }
}];

